				dizzyIconSwirl: function(dizzy) {
					if (result.confused == 1 && result.magicBut.get_visible() == 1) {
						this.dizzyIcon.set_visible(true);
						dizzy = this.dizzyIcon;
						dizzy.set_rotation(dizzy.get_rotation() + 11);
						result.magicBut.removeEventListener("mouseDown", createObjectMixin(this, this.magicScreenShowForwarder));
					} else {
						this.dizzyIcon.set_visible(false);
					}
				},
				charBounceBack: function() {
					this.charStateTimer.reset();
					if (this.up == 1) {
						var targetCharacter = result.char[0];
						targetCharacter.set_y(targetCharacter.get_y() + (7 + ((result.speed + result.eSpeed) / 5 + this.ninSpeed)));
					}
					if (this.down == 1) {
						targetCharacter = result.char[0];
						targetCharacter.set_y(targetCharacter.get_y() - (7 + ((result.speed + result.eSpeed) / 5 + this.ninSpeed)));
					}
					if (this.left == 1) {
						targetCharacter = result.char[0];
						targetCharacter.set_x(targetCharacter.get_x() + (7 + ((result.speed + result.eSpeed) / 5 + this.ninSpeed)));
					}
					if (this.right == 1) {
						targetCharacter = result.char[0];
						targetCharacter.set_x(targetCharacter.get_x() - (7 + ((result.speed + result.eSpeed) / 5 + this.ninSpeed)));
					}
					result.charBottom[0].set_x(result.char[0].get_x());
					result.charBottom[0].set_y(result.char[0].get_y() + 54);
					this.colCharBottom.set_x(result.char[0].get_x());
					this.colCharBottom.set_y(result.char[0].get_y() + 50);
				},
