				enterBounceback: function() {
					if (this.charState >= 0 && this.charState <= 3) {
						var charMovementDirection = result.char[0];
						charMovementDirection.set_y(charMovementDirection.get_y() - 10);
					}
					if (this.charState >= 4 && this.charState <= 7) {
						charMovementDirection = result.char[0];
						charMovementDirection.set_y(charMovementDirection.get_y() + 10);
					}
					if (this.charState >= 8 && this.charState <= 11) {
						charMovementDirection = result.char[0];
						charMovementDirection.set_x(charMovementDirection.get_x() + 10);
					}
					if (this.charState >= 12 && this.charState <= 15) {
						charMovementDirection = result.char[0];
						charMovementDirection.set_x(charMovementDirection.get_x() - 10);
					}
					result.charBottom[0].set_x(result.char[0].get_x());
					result.charBottom[0].set_y(result.char[0].get_y() + 54);
				},
				warpFunc: function() {
					if (result.area == 11 || result.area == 2 || result.area == 3) {
						if (result.north == 22 && result.east == 11) {
							result.north = 21;
							result.east = 13;
						} else if (result.north == 21 && result.east == 13) {
							result.north = 22;
							result.east = 11;
						} else if (result.north == 22 && result.east == 10) {
							result.east = 13;
						} else if (result.north == 22 && result.east == 13) {
							result.east = 10;
						} else if (result.north == 23 && result.east == 10) {
							result.north = 24;
							result.east = 13;
						} else if (result.north == 24 && result.east == 13) {
							result.north = 23;
							result.east = 10;
						} else if (result.north == 23 && result.east == 14) {
							result.north = 24;
							result.east = 10;
						} else if (result.north == 24 && result.east == 10) {
							result.north = 23;
							result.east = 14;
						} else if (result.north == 21 && result.east == 9) {
							result.north = 22;
							result.east = 12;
						} else if (result.north == 22 && result.east == 12) {
							result.north = 21;
							result.east = 9;
						} else if (result.north == 9 && result.east == 21) {
							result.north = 12;
							result.east = 14;
						} else if (result.north == 12 && result.east == 14) {
							result.north = 9;
							result.east = 21;
						}
						this.newScreen();
						__createObject.loca();
						result.char[0].set_x(result.gTeleTile.get_x() + 85);
						result.char[0].set_y(result.gTeleTile.get_y() - 50);
						if (result.north == 22 && result.east == 12) {
							result.char[0].set_y(result.gTeleTile.get_y() + 65);
							result.char[0].set_x(result.gTeleTile.get_x() - 25);
						}
						if (result.north == 9 && result.east == 21) {
							result.char[0].set_x(result.gTeleTile.get_x() + 50);
							result.char[0].set_y(result.gTeleTile.get_y() - 50);
						}
						this.moveChar();
					}
				},
				warpScreenShow: function() {
					console.log("warp screen");
					if (this.fightMode == 1) {
						this.removeProblem();
					} else if (this.fightMode == 0) {
						this.removeListeners();
					}
					this.itemFormat.size = 45;
					this.itemFormat.color = 16777215;
					result.removeButtons();
					result.armorScreen.set_visible(true);
					this.xVar = 20;
					this.yVar = 70;
					this.shopMess.set_text("Where would you like to warp?");
					this.shopMess.setTextFormat(result.shopMesFormat);
					this.shopMess.set_y(60);
					this.shopMess.set_visible(true);
					this.shopMess.set_alpha(1);
					this.innerCounter = 0;
					for (this.yVar = 110; this.innerCounter < 9;) {
						result.itemDisplay[this.innerCounter].set_height(45);
						result.itemDisplay[this.innerCounter].set_y(this.yVar + this.innerCounter * 45);
						result.itemDisplay[this.innerCounter].set_x(50);
						if (this.innerCounter == 0) {
							result.itemDisplay[0].set_text("South of Dyce");
						}
						if (this.innerCounter == 1) {
							result.itemDisplay[1].set_text("Forrest of Fayth");
						}
						if (this.innerCounter == 2) {
							result.itemDisplay[2].set_text("East of Castle Muldivadd");
						}
						if (this.innerCounter == 3) {
							result.itemDisplay[3].set_text("Multiple Mountains");
						}
						if (this.innerCounter == 4) {
							result.itemDisplay[4].set_text("Temple of Tessellation");
						}
						if (this.innerCounter == 5) {
							result.itemDisplay[5].set_text("East of the Scalene Society");
						}
						if (result.quest[result.gTree] > 15 && this.innerCounter == 6) {
							result.itemDisplay[6].set_text("Tomb of the Quarter Hawk");
						}
						if (result.quest[result.gTree] > 18 && this.innerCounter == 7) {
							result.itemDisplay[7].set_text("Garden of Shadowsoul");
						}
						if (result.quest[result.gTree] > 22 && this.innerCounter == 8) {
							result.itemDisplay[8].set_text("Grimsbane");
						}
						result.itemDisplay[this.innerCounter].setTextFormat(this.itemFormat);
						result.itemDisplay[this.innerCounter].set_visible(true);
						if (result.quest[result.gTree] < 16 && this.innerCounter == 6) {
							result.itemDisplay[this.innerCounter].set_visible(false);
						}
						if (result.quest[result.gTree] < 19 && this.innerCounter == 7) {
							result.itemDisplay[this.innerCounter].set_visible(false);
						}
						if (result.quest[result.gTree] < 23 && this.innerCounter == 8) {
							result.itemDisplay[this.innerCounter].set_visible(false);
						}
						this.innerCounter++;
					}
					result.exitButton.set_x(300);
					result.exitButton.set_visible(true);
					this.stage.addEventListener("mouseDown", createObjectMixin(this, this.useWarpHandler));
				},
