							result.messPage = 1;
							if (result.north == 21 && result.east == 20) {
								result.gold += f.parseInt(result.sell.get_text()) * (3 + result.fame);
								result.loot[result.bTusk] -= f.parseInt(result.sell.get_text());
							}
							if (result.north == 13 && result.east == 18) {
								result.gold += f.parseInt(result.sell.get_text()) * (5 + result.fame);
								result.loot[result.bFang] -= f.parseInt(result.sell.get_text());
							}
