				removeWeapons: function() {
					newObserveObject.knockback = false;
					for (this.weapCounter = 0; this.weapCounter < result.weapon.length;) {
						if (result.weapon[this.weapCounter] == 2) {
							result.weapon[this.weapCounter] = 1;
							if (this.weapCounter == 0) {
								result.eStr -= 2;
							} else if (this.weapCounter == 1) {
								result.eStr -= 5;
								result.eSpeed--;
							} else if (this.weapCounter == 2) {
								result.eStr -= 10;
							} else if (this.weapCounter == 3) {
								result.eStr -= 15;
								result.eSpeed -= 2;
							} else if (this.weapCounter == 4) {
								result.eMagic -= 50;
							} else if (this.weapCounter == 5) {
								result.eStr -= 9;
								result.eSpeed -= 4;
							} else if (this.weapCounter == 6) {
								result.eMagic -= 25;
							} else if (this.weapCounter == 7) {
								result.eStr -= 20;
								result.eSpeed++;
							} else if (this.weapCounter == 8) {
								result.eStr -= 50;
								result.eSpeed -= 10;
							} else if (this.weapCounter == 9) {
								result.eStr -= 10;
								result.eMagic -= 100;
								result.eSpeed -= 2;
							} else if (this.weapCounter == 10) {
								result.eStr -= 80;
								result.eMagic -= 50;
								result.eSpeed += 2;
							} else if (this.weapCounter == 11) {
								result.eStr -= 50;
								result.eSpeed -= 3;
							} else if (this.weapCounter == 12) {
								result.eStr -= 5;
								result.eSpeed -= 5;
							} else if (this.weapCounter == 13) {
								result.eStr -= 10;
							} else if (this.weapCounter == 14) {
								result.eStr -= 25;
								result.eMagic -= 200;
							} else if (this.weapCounter == 15) {
								result.eStr -= result.axeVar;
								result.eSpeed -= 2;
							} else if (this.weapCounter == 16) {
								result.eStr -= 100;
							} else if (this.weapCounter == 17) {
								result.eStr -= 30;
								result.eSpeed -= 12;
							} else if (this.weapCounter == 19) {
								result.eStr -= result.aPower;
							}
						}
						this.weapCounter++;
					}
				},
