				lootExitHandler: function(gameButton) {
					if (result.exitButton.hitTestPoint(this.get_mouseX(), this.get_mouseY(), true) && result.exitButton.get_visible() == 1) {
						result.lootScreen.set_visible(false);
						result.exitButton.set_visible(false);
						result.blueOrb.set_visible(false);
						result.greenOrb.set_visible(false);
						result.redOrb.set_visible(false);
						this.keyIcon.set_visible(false);
						this.pendant.set_visible(false);
						result.soulStone.set_visible(false);
						this.aurastoneIcon.set_visible(false);
						this.rubyIcon.set_visible(false);
						this.emarldIcon.set_visible(false);
						this.ringGoldIcon.set_visible(false);
						result.ringHealthIcon.set_visible(false);
						result.ringEvaIcon.set_visible(false);
						this.ringPoiIcon.set_visible(false);
						this.ringMagicIcon.set_visible(false);
						this.ringSkillIcon.set_visible(false);
						result.ringDeathIcon.set_visible(false);
						result.bombIconSmall.set_visible(false);
						this.pupIcon.set_visible(false);
						this.diamondIcon.set_visible(false);
						this.medallionIcon.set_visible(false);
						this.showButtons();
						for (this.innerCounter = 0; this.innerCounter < 100;) {
							result.itemDisplay[this.innerCounter].set_visible(false);
							this.innerCounter++;
						}
						this.stage.removeEventListener("mouseDown", createObjectMixin(this, this.lootExitHandler));
						if (this.fightMode == 0) {
							this.addListeners();
						} else if (this.fightMode == 1 && result.mHP > 0) {
							this.showProblem();
						}
					}
				},
