				pupBoxShow: function() {
					console.log("pup box");
					if (this.fightMode == 1) {
						this.removeProblem();
					} else if (this.fightMode == 0) {
						this.removeListeners();
					}
					this.itemFormat.size = 36;
					this.itemFormat.color = 16776960;
					result.removeButtons();
					result.pupBut.set_visible(true);
					result.pupBox.set_visible(true);
					this.shopMess.set_text("You have " + result.pup + " power ups left.");
					if (result.pup == 1) {
						this.shopMess.set_text("You have " + result.pup + " power up left.");
					}
					this.shopMess.setTextFormat(result.shopMesFormat);
					this.shopMess.set_y(325);
					this.shopMess.set_x(-25);
					this.shopMess.set_visible(true);
					this.shopMess.set_alpha(1);
					result.arrow[0].set_visible(true);
					result.arrow[1].set_visible(true);
					result.itemDisplay[0].set_x(result.arrow[0].get_x() + 60);
					result.itemDisplay[0].set_y(result.arrow[0].get_y() + 10);
					result.itemDisplay[0].set_text("Upgrade health limit to " + Math.floor(result.mxhp + result.mxhp / 20 + result.eHealth) + "?");
					if (result.hp < 1e3) {
						result.itemDisplay[0].set_text("Upgrade health limit to " + Math.floor(result.mxhp + result.mxhp / 10 + result.eHealth) + "?");
					}
					result.itemDisplay[0].setTextFormat(this.itemFormat);
					result.itemDisplay[0].set_visible(true);
					result.itemDisplay[1].set_x(result.arrow[1].get_x() + 60);
					result.itemDisplay[1].set_y(result.arrow[1].get_y() + 10);
					result.itemDisplay[1].set_text("Upgrade magic limit to " + Math.floor(result.mxmp + result.mxmp / 20 + result.eMagic) + "?");
					if (result.mp < 1e3) {
						result.itemDisplay[1].set_text("Upgrade magic limit to " + Math.floor(result.mxmp + result.mxmp / 10 + result.eMagic) + "?");
					}
					result.itemDisplay[1].setTextFormat(this.itemFormat);
					result.itemDisplay[1].set_visible(true);
					result.exitButton.set_x(480);
					result.exitButton.set_y(520);
					result.exitButton.set_visible(true);
					this.stage.addEventListener("mouseDown", createObjectMixin(this, this.pupHandler));
				},
				pupHandler: function(__mouseClickHandler) {
					if (result.arrow[0].hitTestPoint(this.get_mouseX(), this.get_mouseY(), true)) {
						result.mxhp = result.hp < 1e3 ? Math.floor(result.mxhp + result.mxhp / 10) : Math.floor(result.mxhp + result.mxhp / 20);
						result.pup--;
						result.pupUsed++;
						result.hitMax();
						this.pupSound.play();
					} else if (result.arrow[1].hitTestPoint(this.get_mouseX(), this.get_mouseY(), true)) {
						result.mxmp = result.mp < 1e3 ? Math.floor(result.mxmp + result.mxmp / 10) : Math.floor(result.mxmp + result.mxmp / 20);
						result.pup--;
						result.pupUsed++;
						result.hitMax();
						this.pupSound.play();
					}
					if (result.exitButton.hitTestPoint(this.get_mouseX(), this.get_mouseY(), true) && result.exitButton.get_visible() == 1 || result.pup == 0) {
						result.exitButton.set_visible(false);
						result.exitButton.set_x(300);
						result.exitButton.set_y(530);
						this.shopMess.set_visible(false);
						this.shopMess.set_x(0);
						this.shopMess.set_y(60);
						result.pupBox.set_visible(false);
						this.showButtons();
						result.arrow[0].set_visible(false);
						result.arrow[1].set_visible(false);
						result.itemDisplay[0].set_visible(false);
						result.itemDisplay[1].set_visible(false);
						this.stage.removeEventListener("mouseDown", createObjectMixin(this, this.pupHandler));
						if (this.fightMode == 0) {
							this.addListeners();
						} else if (this.fightMode == 1 && result.mHP > 0) {
							this.showProblem();
						}
					} else {
						this.pupBoxShow();
					}
				},
