								this.exploSound.play();
								this.explodeSword.set_x(320);
								this.explodeSword.set_y(result.mob[newObserveObject.mobVar].get_y() + 15);
								this.explodeSword.set_visible(true);
								this.explodeSword.set_alpha(1);
								this.addChild(this.explodeSword);
								result.bombs--;
								result.mHP -= 100;
								result.bombIcon.set_visible(true);
								result.bombDisplay.set_visible(true);
								result.bombDisplay.set_text(f.string(result.bombs));
								result.bombDisplay.setTextFormat(result.shopMesFormat);
								newObserveObject.fightMes[newObserveObject.fightMesCurrent].set_text("Your bomb explodes off the end of your sword, dealing 100 damage!");
